        return '请先输入API Key'

    ep_info = LLM_ENDPOINTS.get(provider)
    if not ep_info:
        return '未知服务商'

    endpoint = ep_info['endpoint']
    model = ep_info['model']

    try:
        if provider == 'claude':
            headers = {
                'x-api-key': api_key,
                'anthropic-version': '2023-06-01',
                'Content-Type': 'application/json',
            }
            data = {
                'model': model,
                'max_tokens': 10,
                'messages': [{'role': 'user', 'content': 'hi'}],
            }
        elif provider == 'zhipu':
            # 智谱GLM使用标准Bearer Token格式
            headers = {
                'Authorization': 'Bearer %s' % api_key,
                'Content-Type': 'application/json',
            }
            data = {
                'model': model,
                'messages': [{'role': 'user', 'content': 'hi'}],
                'max_tokens': 10,
                'stream': False,
            }
        else:
            headers = {
                'Authorization': 'Bearer %s' % api_key,
                'Content-Type': 'application/json',
            }
            data = {
                'model': model,
                'max_tokens': 10,
                'messages': [{'role': 'user', 'content': 'hi'}],
            }

        resp = requests.post(endpoint, headers=headers, json=data, timeout=20)

        if resp.status_code in (200, 201):
            return '%s: 连接成功' % provider
        else:
            # 尝试解析错误信息
            try:
                err_data = resp.json()
                err_msg = err_data.get('error', {}).get('message', '') or str(err_data)[:60]
            except Exception:
                err_msg = resp.text[:60] if resp.text else 'HTTP %d' % resp.status_code
            return '%s: HTTP %d - %s' % (provider, resp.status_code, err_msg)

    except Exception as e:
        return '测试失败: %s' % str(e)[:80]
